* upgrade gdkxft 1.1 to gdkxft 1.2

Fix: [nuzrin@nuzrin /usr/ports/x11]> diff -ruN gdkxft gdkxft-new
PORTNAME=      gdkxft
-PORTVERSION=   1.1
+PORTVERSION=   1.2
 CATEGORIES=    x11
 MASTER_SITES=  http://philrsss.anu.edu.au/~josh/gdkxft/

@@ -29,7 +29,12 @@
 post-install:
        @${MKDIR} ${DOCSDIR}
        @${INSTALL_MAN} ${WRKSRC}/README ${DOCSDIR}
-       @/usr/bin/printf "\nRefer to ${DOCSDIR}/README for details on how to enable gdkxft.\n\n" > \
+       @/usr/bin/printf "\nRefer to ${DOCSDIR}/README for details on how to enable gdkxft.\n\n \
+               You will need to add environment variable LD_PRELOAD=/usr/X11R6/lib/libgdkxft.so.\n \
+               Depending on your X11 configuration, you may need to add the line \n \
+                       export LD_PRELOAD=/usr/X11R6/lib/libgdkxft.so \n \
+               in either ~/.xinitrc or /etc/X11/xinit/xinitrc or /usr/X11R6/bin/startx \n \
+               at the near top of the file before the window manager start.\n\n" > \
                ${PKGMESSAGE}
        @${CAT} ${PKGMESSAGE}

echo $ac_n "checking for libgdk.la""... $ac_c" 1>&6
- echo "configure:1747: checking for libgdk.la" >&5
+ echo "configure:2155: checking for libgdk.la" >&5
 -GTK_PREFIX=`gtk-config --prefix`
 +GTK_PREFIX=`$GTK_CONFIG --prefix`
  GDK_LIB_PREFIX=$GTK_PREFIX/lib
@@ -15,10 +12,10 @@
  if test -r $GDK_LA
  then echo "$ac_t""$GDK_LA" 1>&6
  else echo "$ac_t""not found" 1>&6 ; { echo "configure: error: libgdk.la is missing" 1>&2; exit 1; }
-@@ -1754,7 +1754,7 @@
+@@ -2162,7 +2162,7 @@

