 -GDK_DLOPEN_NAME=`sed -n -e "s/^dlname='\\([^']*\\)'$/\\1/p" $GDK_LA`
 +GDK_DLOPEN_NAME="libgdk12.so"
  if test x$GDK_DLOPEN_NAME = x
#include <X11/Xlib.h>
